// src/context/AuthContext.js - React Auth Context
// ============================================================================

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { authService } from '../services/authService';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(authService.isAuthenticated());
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);
  const [user, setUser] = useState(authService.getUserInfo());

  useEffect(() => {
    const unsubscribe = authService.subscribe((authenticated) => {
      setIsAuthenticated(authenticated);
      setUser(authenticated ? authService.getUserInfo() : null);
    });
    return unsubscribe;
  }, []);

  const login = useCallback(async (returnUrl) => {
    setIsLoading(true);
    setError(null);
    try {
      await authService.login(returnUrl);
    } catch (err) {
      setError(err.message);
      setIsLoading(false);
    }
  }, []);

  const handleCallback = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const returnUrl = await authService.handleCallback();
      setIsLoading(false);
      return returnUrl;
    } catch (err) {
      setError(err.message);
      setIsLoading(false);
      throw err;
    }
  }, []);

  const logout = useCallback(async () => {
    setIsLoading(true);
    await authService.logout();
    setIsLoading(false);
  }, []);

  const value = {
    isAuthenticated,
    isLoading,
    error,
    user,
    login,
    logout,
    handleCallback,
    getAccessToken: () => authService.getAccessToken(),
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

