import React, { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export function CallbackPage() {
  const { handleCallback } = useAuth();
  const navigate = useNavigate();
  const [error, setError] = useState(null);
  const processedRef = useRef(false);

  useEffect(() => {
    // Prevent double-processing in React StrictMode
    if (processedRef.current) return;
    processedRef.current = true;

    const processCallback = async () => {
      try {
        const returnUrl = await handleCallback();
        navigate(returnUrl, { replace: true });
      } catch (err) {
        console.error('Callback processing failed:', err);
        setError(err.message);
      }
    };

    processCallback();
  }, [handleCallback, navigate]);

  if (error) {
    return (
      <div style={callbackStyles.container}>
        <div style={callbackStyles.card}>
          <h2 style={callbackStyles.errorTitle}>Authentication Failed</h2>
          <p style={callbackStyles.errorMessage}>{error}</p>
          <button
            onClick={() => navigate('/login', { replace: true })}
            style={callbackStyles.retryButton}
          >
            Return to Login
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={callbackStyles.container}>
      <div style={callbackStyles.card}>
        <div style={callbackStyles.spinner}></div>
        <p style={callbackStyles.message}>Completing authentication...</p>
      </div>
    </div>
  );
}

